export type ProjectPreviewSource = {
	path: string;
	type: 'video/webm' | 'video/mp4';
};

export type ProjectPreviewAsset = {
	posterPath: string;
	sources: ProjectPreviewSource[];
};

// Generated by scripts/publish-project-preview.mjs
export const projectPreviewMedia: Record<string, ProjectPreviewAsset> = {
	'foia-search': {
		posterPath: '/project-previews/foia-search/poster.jpg',
		sources: [
			{
				path: '/project-previews/foia-search/preview.webm',
				type: 'video/webm'
			},
			{
				path: '/project-previews/foia-search/preview.mp4',
				type: 'video/mp4'
			}
		]
	}
};

export function getProjectPreviewMedia(projectId: string): ProjectPreviewAsset | null {
	return projectPreviewMedia[projectId] ?? null;
}
